/**
 * Mock data for the Data › Payments & Settlements record-explorer page.
 *
 * Ported from /Users/mac/Downloads/MAGELLAN UX/Data/magellan-data-payments.html
 * Currency converted ฿ → $ (same digits, $ symbol) per the Magellan currency rule.
 *
 * A payment is real money movement — NOT the order total. The gateway takes a
 * fee; the net settles LATER in a batch. This page is where the money actually
 * is. The template builds 52 deterministic records with a seeded RNG (mulberry32,
 * seed 73); we reproduce that generator verbatim so the rows are stable across
 * renders, then freeze the array (sorted newest-first) and expose typed column /
 * filter / calendar metadata plus the pure helpers the page reuses.
 */

/* ─────────────────────────── Types ─────────────────────────── */

export type Method = "Credit Card" | "PromptPay" | "Bank Transfer";
export type Processor = "Omise" | "Stripe" | "manual";
export type SettleStatus = "settled" | "in-batch" | "pending" | "refunded";

export interface PaymentRecord {
  id: string;
  orderId: string;
  /** ISO date (YYYY-MM-DD) of capture — used for date-range filtering */
  date: string;
  /** ms epoch of capture, for stable date sort */
  ts: number;
  time: string;
  customer: string;
  method: Method;
  processor: Processor;
  feeRate: number;
  gross: number;
  fee: number;
  net: number;
  status: SettleStatus;
  settleDays: number;
  /** ms epoch of expected/actual settlement, for the trend bucketing & sort */
  settleTs: number;
  settleDateStr: string;
  /** timeline steps: [label, timestamp] */
  tl: Array<[string, string]>;
}

export type ColumnKey =
  | "id"
  | "customer"
  | "method"
  | "gross"
  | "fee"
  | "net"
  | "status"
  | "settleDate"
  | "orderId";

export interface ColumnDef {
  k: ColumnKey;
  label: string;
  on: boolean;
  num?: boolean;
  fixed?: boolean;
}

export type FilterKey = "method" | "processor" | "status";

/* ─────────────────────────── Seeded RNG (mulberry32, seed 73) ─────────────────────────── */

function mulberry32(a: number) {
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
const rng = mulberry32(73);
const pick = <T>(arr: readonly T[]): T => arr[Math.floor(rng() * arr.length)];
const between = (a: number, b: number) => a + Math.floor(rng() * (b - a + 1));

const FIRST = [
  "Somchai", "Nattaya", "Preecha", "Siriporn", "Wirote", "Apinya", "Thanawat",
  "Kanya", "Chaiwat", "Ratana", "Niran", "Sukanya", "Prasert", "Malee", "Anan",
  "Ploy", "Korn", "Benjamas", "Wichai", "Suda", "Decha", "Pim", "Krit", "Wanida",
  "Surasak", "Nicha", "Phong", "Araya", "Tawan", "Mali",
] as const;
const LAST = [
  "Rakthong", "Sripongpun", "Charoensuk", "Thongsuk", "Janphen", "Mongkol",
  "Boonmee", "Phetcharat", "Saetang", "Wongphan", "Intara", "Chaiyo", "Pimchan",
  "Sutthi", "Krairit", "Hoeft", "Veerasak", "Anong", "Damrong", "Klahan",
] as const;

/* method, processor, feeRate, settleDays — the gateway matrix from the template */
const PGATEWAYS: ReadonlyArray<[Method, Processor, number, number]> = [
  ["Credit Card", "Omise", 0.0365, 2],
  ["Credit Card", "Stripe", 0.0345, 2],
  ["PromptPay", "Omise", 0.0125, 1],
  ["Bank Transfer", "manual", 0.0, 0],
];

const TODAY = new Date(2026, 4, 26);

function fmt(d: Date): string {
  return d
    .toLocaleString("en-GB", { day: "numeric", month: "short", hour: "2-digit", minute: "2-digit" })
    .replace(",", "");
}

function genPayment(i: number): PaymentRecord {
  const [method, processor, feeRate, settleDays] = pick(PGATEWAYS);
  // gross amount paid by the customer (USD — same digits as the template ฿)
  const gross = Math.round((1290 + rng() * 6000) / 10) * 10;
  const fee = Math.round(gross * feeRate);
  const net = gross - fee;
  const orderId = "#" + (64000 - between(10, 950));

  // dates — anchored to 26 May 2026
  const daysAgo = between(0, 29);
  const dt = new Date(TODAY);
  dt.setDate(dt.getDate() - daysAgo);
  dt.setHours(between(8, 21), between(0, 59));

  // settlement: settled if enough days passed; else pending / in-batch
  const settleDate = new Date(dt);
  settleDate.setDate(settleDate.getDate() + settleDays);

  let status: SettleStatus;
  if (method === "Bank Transfer") {
    status = rng() < 0.85 ? "settled" : "pending";
  } else if (daysAgo >= settleDays + 1) {
    status = "settled";
  } else if (daysAgo >= settleDays) {
    status = "in-batch";
  } else {
    status = "pending";
  }
  // a small share are clawed back
  const clawedBack = rng() < 0.08;
  if (clawedBack) status = "refunded";

  // timeline
  const tl: Array<[string, string]> = [];
  let c = new Date(dt);
  tl.push(["Payment captured", fmt(c)]);
  if (status !== "pending") {
    c = new Date(c.getTime() + 3600000);
    tl.push([`Fee deducted · $${fee.toLocaleString()}`, fmt(c)]);
  }
  if (status === "settled") {
    tl.push([`Settled to bank · $${net.toLocaleString()}`, fmt(settleDate)]);
  } else if (status === "in-batch") {
    tl.push(["In settlement batch", fmt(settleDate)]);
  } else if (status === "refunded") {
    c = new Date(c.getTime() + 86400000);
    tl.push(["Refunded · clawed back", fmt(c)]);
  }

  return {
    id: "PAY-" + (70000 + i * 7),
    orderId,
    date: dt.toISOString().slice(0, 10),
    ts: dt.getTime(),
    time: dt.toLocaleString("en-GB", { hour: "2-digit", minute: "2-digit" }),
    customer: `${pick(FIRST)} ${pick(LAST)}`,
    method,
    processor,
    feeRate,
    gross,
    fee,
    net,
    status,
    settleDays,
    settleTs: settleDate.getTime(),
    settleDateStr: settleDate.toISOString().slice(0, 10),
    tl,
  };
}

/* The 52 deterministic payment records, newest first. */
export const PAYMENTS: PaymentRecord[] = Array.from({ length: 52 }, (_, i) =>
  genPayment(i + 1),
).sort((a, b) => b.ts - a.ts);

